// @compatible         edge
// @compatible         opera
// @compatible         safari
// @compatible         kiwi
// @compatible         qq
// @compatible         via
// @compatible         brave
// @version            2026.06.13.0002
// @grant              GM_setValue
// @grant              GM_getValue
